/* eslint-disable class-methods-use-this */
import * as THREE from 'three';
import { HeadMaskMesh } from '../mesh/headmaskmesh.js';
const itemFilename = '__zappar_threejs_head_mask_mesh';
/**
 * Loader for HeadMaskMesh objects.
 * @see https://docs.zap.works/universal-ar/web-libraries/threejs/face-tracking/
 */
export class HeadMaskMeshLoader extends THREE.Loader {
    // Implementation that handles both signatures
    load(urlOrOnLoad, onLoadOrProgress, onProgressOrError, onError) {
        // Check if we're using the new pattern (first arg is string URL)
        const isNewPattern = typeof urlOrOnLoad === 'string';
        if (isNewPattern) {
            // New pattern - returns void
            // We don't actually need the URL for HeadMaskMesh but we accept it for interface compatibility
            const onLoadCallback = onLoadOrProgress;
            const errorCallback = onError;
            this.manager.itemStart(itemFilename);
            const mesh = new HeadMaskMesh(() => {
                this.manager.itemEnd(itemFilename);
            }, () => {
                if (errorCallback)
                    errorCallback(new Error('Failed to create HeadMaskMesh'));
                this.manager.itemError(itemFilename);
                this.manager.itemEnd(itemFilename);
            });
            // Call the callback with the mesh
            onLoadCallback(mesh);
            return;
        }
        else {
            // Original implementation - returns HeadMaskMesh
            const onLoad = urlOrOnLoad;
            const onError = onProgressOrError;
            this.manager.itemStart(itemFilename);
            return new HeadMaskMesh(() => {
                if (onLoad)
                    onLoad();
                this.manager.itemEnd(itemFilename);
            }, () => {
                if (onError)
                    onError();
                this.manager.itemError(itemFilename);
                this.manager.itemEnd(itemFilename);
            });
        }
    }
    /**
     * @ignore
     */
    parse() { }
}
